<template><main class='page'><header class='page-header'><p class='hello'>🍳 我的厨房</p><h1 class='page-title'>今天想吃什么？</h1><p class='page-subtitle'>开源菜品库读取数据，轮播推荐、分类点菜、步骤图跟做、自动生成买菜清单。</p></header><section class='search card'><span>🔍</span><input v-model='keyword' placeholder='搜索菜品、口味、食材'/></section><section v-if='banners.length' class='carousel'><div class='track' :style='{transform:`translateX(-${currentBanner*100}%)`}'><article v-for='banner in banners' :key='banner.id' class='slide' @click='openBanner(banner)'><img :src='banner.image'/><div class='shade'></div><div class='copy'><span>今日推荐</span><h2>{{banner.title}}</h2><p>{{banner.subtitle}}</p></div></article></div><div class='dots'><button v-for='(_,i) in banners' :key='i' :class='{active:i===currentBanner}' @click.stop='currentBanner=i'></button></div></section><section class='quick card'><button @click='oneClickMenu'>一键生成三菜一汤</button><button @click='$router.push("/cart")'>查看今日菜单</button></section><section class='section'><h2 class='section-title'>热门菜系</h2><div class='cuisine-grid'><button v-for='item in cuisines' :key='item.name' class='cuisine card' @click='goCuisine(item.name)'><span>{{item.icon}}</span><strong>{{item.name}}</strong><em>{{item.desc}}</em></button></div></section><section class='section'><h2 class='section-title'>{{keyword?'搜索结果':'推荐菜品'}}</h2><DishCard v-for='dish in shownDishes' :key='dish.id' :dish='dish'/></section></main></template><script setup>import{computed,onMounted,onUnmounted,ref}from'vue';import{useRouter}from'vue-router';import DishCard from'../components/DishCard.vue';import{useRecipes}from'../composables/useRecipes';import{addCart}from'../utils/storage';const router=useRouter();const{dishes,cuisines,banners,loadRecipes}=useRecipes();const keyword=ref(''),currentBanner=ref(0);let timer;onMounted(async()=>{await loadRecipes();timer=setInterval(()=>{if(banners.value.length)currentBanner.value=(currentBanner.value+1)%banners.value.length},3200)});onUnmounted(()=>clearInterval(timer));const shownDishes=computed(()=>{const key=keyword.value.trim();if(key)return dishes.value.filter(d=>[d.name,d.cuisine,d.category,d.taste,d.description,...d.ingredients].join('').includes(key));return dishes.value.slice(0,10)});function goCuisine(name){router.push({path:'/category',query:{cuisine:name}})}function openBanner(b){const id=b.dishIds?.[0];if(id)router.push(`/dish/${id}`)}function oneClickMenu(){[...dishes.value].sort(()=>Math.random()-.5).slice(0,4).forEach(d=>addCart({...d,selectedSpec:d.specs?.[0],cartId:Date.now()+Math.random()}));alert('已生成今日菜单')}</script><style scoped>.hello{margin:0 0 8px;color:var(--blue);font-size:15px;font-weight:900}.search{height:54px;display:flex;align-items:center;gap:10px;padding:0 18px}.search input{flex:1;border:0;outline:0;background:transparent;font-size:15px}.carousel{position:relative;margin-top:18px;border-radius:30px;overflow:hidden;height:238px;box-shadow:0 20px 50px rgba(0,122,255,.18)}.track{height:100%;display:flex;transition:transform .45s cubic-bezier(.2,.8,.2,1)}.slide{position:relative;min-width:100%;height:100%}.slide img{width:100%;height:100%;object-fit:cover}.shade{position:absolute;inset:0;background:linear-gradient(to top,rgba(0,0,0,.55),rgba(0,0,0,.05))}.copy{position:absolute;left:20px;right:20px;bottom:22px;color:#fff}.copy span{display:inline-flex;padding:6px 10px;border-radius:999px;background:rgba(255,255,255,.2);font-size:12px;font-weight:900}.copy h2{margin:10px 0 6px;font-size:25px}.copy p{margin:0;color:rgba(255,255,255,.85);font-size:14px}.dots{position:absolute;right:18px;bottom:18px;display:flex;gap:7px}.dots button{width:7px;height:7px;border:0;border-radius:999px;background:rgba(255,255,255,.45);padding:0}.dots button.active{width:22px;background:#fff}.quick{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:16px;padding:12px}.quick button{height:44px;border:0;border-radius:18px;background:#eef6ff;color:var(--blue);font-weight:900}.quick button:first-child{background:var(--blue);color:#fff}.cuisine-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:9px}.cuisine{border:0;padding:14px 5px;text-align:center;min-height:112px}.cuisine span{display:block;font-size:28px}.cuisine strong{display:block;margin-top:8px;font-size:14px}.cuisine em{display:block;margin-top:5px;font-style:normal;color:var(--sub);font-size:10px;line-height:1.3}</style>
